package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.Corrida; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Reptil; public class Iguana extends Reptil implements Corrida { public Iguana(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " faz um som sibilante discreto."); } public void comer() { System.out.println(getNome() + " está comendo folhas e vegetais."); } public void correr() { System.out.println(getNome() + " está correndo entre galhos e pedras."); } }
